#include <pthread.h>
#include <stdio.h>
#include <stdlib.h>

#define NUM_THREADS 5

void* printHello(void* threadID) {
    long tid;
    tid = (long)threadID;
    printf("Hello from thread #%ld\n", tid);
    pthread_exit(NULL);
}

int main() {
    pthread_t threads[NUM_THREADS];
    int rc;
    long t;

    for(t = 0; t < NUM_THREADS; t++) {
        printf("Creating thread %ld\n", t);
        rc = pthread_create(&threads[t], NULL, printHello, (void*)t);
        if (rc) {
            printf("ERROR; return code from pthread_create() is %d\n", rc);
            exit(-1);
        }
    }

    // Wait for all threads to complete
    for(t = 0; t < NUM_THREADS; t++) {
        pthread_join(threads[t], NULL);
    }

    printf("All threads completed\n");
    pthread_exit(NULL);
    return 0;
}

#include <pthread.h>
#include <stdio.h>
#include <stdlib.h>

#define NUM_THREADS 1000

int sharedCounter = 0;
pthread_mutex_t mutex = PTHREAD_MUTEX_INITIALIZER;

void* incrementCounter(void* arg) {
    int i;
    for(i = 0; i < 1000; i++) {
        pthread_mutex_lock(&mutex);    // Acquire lock
        sharedCounter++;               // Critical section
        pthread_mutex_unlock(&mutex);  // Release lock
    }
    pthread_exit(NULL);
}

int main() {
    pthread_t threads[NUM_THREADS];
    int rc;
    long t;

    // Create threads
    for(t = 0; t < NUM_THREADS; t++) {
        rc = pthread_create(&threads[t], NULL, incrementCounter, NULL);
        if (rc) {
            printf("Error: return code is %d\n", rc);
            exit(-1);
        }
    }

    // Wait for completion
    for(t = 0; t < NUM_THREADS; t++) {
        pthread_join(threads[t], NULL);
    }

    printf("Final counter value: %d (expected: %d)\n", 
           sharedCounter, NUM_THREADS * 1000);
    pthread_exit(NULL);
    return 0;
}

public class ThreadDemo {

    // Method 1: Extending Thread class
    static class MyThread extends Thread {
        private String threadName;

        public MyThread(String name) {
            this.threadName = name;
        }

        @Override
        public void run() {
            System.out.println("Thread " + threadName + " is running");
            try {
                sleep(100);  // Simulate work
            } catch (InterruptedException e) {
                e.printStackTrace();
            }
            System.out.println("Thread " + threadName + " exiting");
        }
    }

    // Method 2: Implementing Runnable interface
    static class MyRunnable implements Runnable {
        private String threadName;

        public MyRunnable(String name) {
            this.threadName = name;
        }

        @Override
        public void run() {
            System.out.println("Runnable " + threadName + " running");
        }
    }

    public static void main(String[] args) {
        // Method 1: Using Thread class
        MyThread t1 = new MyThread("Thread-1");
        t1.start();

        // Method 2: Using Runnable
        Runnable r = new MyRunnable("Runnable-1");
        Thread t2 = new Thread(r);
        t2.start();

        // Using lambda (Java 8+)
        Thread t3 = new Thread(() -> {
            System.out.println("Lambda thread running");
        });
        t3.start();

        // Wait for threads to complete
        try {
            t1.join();
            t2.join();
            t3.join();
        } catch (InterruptedException e) {
            e.printStackTrace();
        }

        System.out.println("All threads completed");
    }
}
